"use client";

import Link from "next/link";
import { usePathname } from "next/navigation";
import { useState } from "react";

const navItems = [
  { name: "dashboard", href: "/dashboard" },
  { name: "cortex", href: "/cortex" },
  {
    name: "labs",
    href: "/labs/k0",
    subitems: [
      { name: "k0", href: "/labs/k0" },
      { name: "brainstorming", href: "/labs/brainstorming" },
      { name: "system", href: "/labs/system" },
      { name: "execution", href: "/labs/execution" },
      { name: "pitch", href: "/labs/pitch" },
    ],
  },
  { name: "projects", href: "/projects" },
  { name: "settings", href: "/settings" },
];

export function SidebarNav() {
  const pathname = usePathname();
  const [labsOpen, setLabsOpen] = useState(pathname?.startsWith("/labs"));

  const isActive = (href: string) => pathname === href;
  const isLabsActive = pathname?.startsWith("/labs");

  return (
    <aside className="w-64 h-screen bg-zinc-900 border-r border-white/10 flex flex-col fixed left-0 top-0">
      <div className="p-6 border-b border-white/10">
        <h1 className="text-xl font-bold text-white">k3rn</h1>
        <p className="text-xs text-zinc-500 mt-1">app shell v1</p>
      </div>

      <nav className="flex-1 p-4 space-y-1">
        {navItems.map((item) => {
          if (item.subitems) {
            return (
              <div key={item.name}>
                <button
                  onClick={() => setLabsOpen(!labsOpen)}
                  className={`w-full text-left px-4 py-2.5 rounded-lg text-sm font-medium transition-all ${
                    isLabsActive
                      ? "bg-white/10 text-white"
                      : "text-zinc-400 hover:text-white hover:bg-white/5"
                  }`}
                >
                  <span className="flex items-center justify-between">
                    {item.name}
                    <svg
                      className={`w-4 h-4 transition-transform ${
                        labsOpen ? "rotate-180" : ""
                      }`}
                      fill="none"
                      stroke="currentColor"
                      viewBox="0 0 24 24"
                    >
                      <path
                        strokeLinecap="round"
                        strokeLinejoin="round"
                        strokeWidth={2}
                        d="M19 9l-7 7-7-7"
                      />
                    </svg>
                  </span>
                </button>
                {labsOpen && (
                  <div className="mt-1 ml-4 space-y-1">
                    {item.subitems.map((subitem) => (
                      <Link
                        key={subitem.name}
                        href={subitem.href}
                        className={`block px-4 py-2 rounded-lg text-sm transition-all ${
                          isActive(subitem.href)
                            ? "bg-white/5 text-white font-medium"
                            : "text-zinc-500 hover:text-white hover:bg-white/5"
                        }`}
                      >
                        {subitem.name}
                      </Link>
                    ))}
                  </div>
                )}
              </div>
            );
          }

          return (
            <Link
              key={item.name}
              href={item.href}
              className={`block px-4 py-2.5 rounded-lg text-sm font-medium transition-all ${
                isActive(item.href)
                  ? "bg-white/10 text-white"
                  : "text-zinc-400 hover:text-white hover:bg-white/5"
              }`}
            >
              {item.name}
            </Link>
          );
        })}
      </nav>

      <div className="p-4 border-t border-white/10">
        <p className="text-xs text-zinc-500">
          © 2026 k3rn
        </p>
      </div>
    </aside>
  );
}

