'use client'

import { ButtonHTMLAttributes, forwardRef } from 'react'
import { cn } from '@/lib/utils'

interface ButtonProps extends ButtonHTMLAttributes<HTMLButtonElement> {
  variant?: 'primary' | 'secondary' | 'ghost'
  size?: 'sm' | 'md' | 'lg'
}

export const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  ({ className, variant = 'primary', size = 'md', children, ...props }, ref) => {
    return (
      <button
        ref={ref}
        className={cn(
          // Base
          'inline-flex items-center justify-center font-semibold transition-all',
          'disabled:opacity-50 disabled:cursor-not-allowed',

          // Variants
          {
            // Primary (gradient orange)
            'bg-gradient-to-r from-orange-500 via-orange-600 to-orange-700 text-white': 
              variant === 'primary',
            'hover:scale-[1.02] hover:brightness-110': 
              variant === 'primary' && !props.disabled,

            // Secondary (transparent + border)
            'bg-transparent border border-neutral-800 text-fg-primary': 
              variant === 'secondary',
            'hover:bg-neutral-900': 
              variant === 'secondary' && !props.disabled,

            // Ghost
            'bg-transparent text-neutral-400': 
              variant === 'ghost',
            'hover:text-fg-primary hover:bg-neutral-900/50': 
              variant === 'ghost' && !props.disabled,
          },

          // Sizes
          {
            'px-4 py-2 text-sm rounded-md': size === 'sm',
            'px-6 py-3 text-base rounded-lg': size === 'md',
            'px-8 py-4 text-lg rounded-xl': size === 'lg',
          },

          className
        )}
        {...props}
      >
        {children}
      </button>
    )
  }
)

Button.displayName = 'Button'
