import { forwardRef, InputHTMLAttributes } from "react";
import { cn } from "@/lib/utils";

export interface InputProps extends InputHTMLAttributes<HTMLInputElement> {
  variant?: "default" | "error";
  label?: string;
  helperText?: string;
  errorMessage?: string;
}

const Input = forwardRef<HTMLInputElement, InputProps>(
  (
    {
      className,
      variant = "default",
      label,
      helperText,
      errorMessage,
      type = "text",
      ...props
    },
    ref
  ) => {
    const isError = variant === "error" || !!errorMessage;

    return (
      <div className="w-full">
        {label && (
          <label className="block text-sm font-medium text-fg-secondary mb-2">
            {label}
          </label>
        )}
        <input
          ref={ref}
          type={type}
          className={cn(
            "w-full px-4 py-2.5 bg-bg-elevated border-2 rounded-lg text-fg-primary placeholder:text-fg-tertiary transition-all duration-300 focus:outline-none focus:ring-2 focus:ring-offset-2 focus:ring-offset-bg-base disabled:opacity-50 disabled:cursor-not-allowed",
            isError
              ? "border-error focus:border-error focus:ring-error"
              : "border-neutral-800 focus:border-orange-500 focus:ring-orange-500 hover:border-neutral-700",
            className
          )}
          {...props}
        />
        {(helperText || errorMessage) && (
          <p
            className={cn(
              "mt-1.5 text-sm",
              isError ? "text-error" : "text-fg-tertiary"
            )}
          >
            {errorMessage || helperText}
          </p>
        )}
      </div>
    );
  }
);

Input.displayName = "Input";

export default Input;

