"use client";

import { useState, useRef, ChangeEvent, FormEvent } from "react";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";
import Button from "@/components/ui/Button";

interface BrainDumpInputProps {
  onSubmit: (text: string) => void;
  isLoading?: boolean;
  placeholder?: string;
  maxLength?: number;
  quickActions?: string[];
}

export default function BrainDumpInput({
  onSubmit,
  isLoading = false,
  placeholder = "Décrivez votre idée de projet en quelques mots...",
  maxLength = 2000,
  quickActions = [
    "App mobile santé",
    "SaaS B2B",
    "Marketplace",
    "IA générative",
  ],
}: BrainDumpInputProps) {
  const [text, setText] = useState("");
  const [isFocused, setIsFocused] = useState(false);
  const textareaRef = useRef<HTMLTextAreaElement>(null);

  const handleChange = (e: ChangeEvent<HTMLTextAreaElement>) => {
    const value = e.target.value;
    if (value.length <= maxLength) {
      setText(value);
    }
  };

  const handleSubmit = (e: FormEvent) => {
    e.preventDefault();
    if (text.trim() && !isLoading) {
      onSubmit(text);
    }
  };

  const handleQuickAction = (action: string) => {
    setText(action);
    textareaRef.current?.focus();
  };

  const percentage = (text.length / maxLength) * 100;
  const isNearLimit = percentage >= 90;
  const isAtLimit = percentage >= 100;

  return (
    <motion.div
      initial={{ opacity: 0, y: 20 }}
      animate={{ opacity: 1, y: 0 }}
      transition={{ duration: 0.5 }}
      className="w-full max-w-3xl mx-auto"
    >
      <form onSubmit={handleSubmit} className="space-y-4">
        {/* Textarea avec gradient border on focus */}
        <div className="relative">
          {/* Gradient border effect */}
          <div
            className={cn(
              "absolute inset-0 rounded-2xl bg-gradient-to-r from-orange-500 via-orange-600 to-orange-700 opacity-0 blur-sm transition-opacity duration-300",
              isFocused && "opacity-50"
            )}
          />

          {/* Textarea */}
          <textarea
