          <textarea
            ref={textareaRef}
            value={text}
            onChange={handleChange}
            onFocus={() => setIsFocused(true)}
            onBlur={() => setIsFocused(false)}
            placeholder={placeholder}
            className={cn(
              "relative w-full min-h-[180px] px-6 py-5 bg-bg-elevated border-2 rounded-2xl text-fg-primary placeholder:text-fg-tertiary resize-none transition-all duration-300 focus:outline-none focus:ring-2 focus:ring-orange-500 focus:ring-offset-2 focus:ring-offset-bg-base",
              isFocused
                ? "border-orange-500 shadow-orange"
                : "border-neutral-800 hover:border-neutral-700"
            )}
            disabled={isLoading}
          />
        </div>

        {/* Quick actions pills */}
        {quickActions.length > 0 && (
          <div className="flex flex-wrap gap-2">
            <span className="text-xs text-fg-tertiary self-center">
              Exemples rapides :
            </span>
            {quickActions.map((action, index) => (
              <button
                key={index}
                type="button"
                onClick={() => handleQuickAction(action)}
                className="px-3 py-1 text-xs bg-neutral-900 text-fg-secondary border border-neutral-800 rounded-full hover:border-neutral-700 hover:text-fg-primary transition-all duration-200 hover:scale-105"
                disabled={isLoading}
              >
                {action}
              </button>
            ))}
          </div>
        )}

        {/* Character count + Submit button */}
        <div className="flex items-center justify-between gap-4">
          {/* Character count */}
          <div className="text-sm">
            <span
              className={cn(
                "transition-colors duration-200",
                isAtLimit
                  ? "text-error font-medium"
                  : isNearLimit
                  ? "text-warning"
                  : "text-fg-tertiary"
              )}
            >
              {text.length} / {maxLength}
            </span>
