"use client";

import Link from "next/link";
import { motion } from "framer-motion";
import { cn } from "@/lib/utils";
import { formatRelativeTime } from "@/lib/date";
import { cardHover } from "@/lib/animations";

interface ProjectCardProps {
  id: string;
  title: string;
  description: string;
  thumbnail?: string | null;
  completionRate: number;
  features: number;
  status: "package-ready" | "draft";
  createdAt: Date;
}

export default function ProjectCard({
  id,
  title,
  description,
  thumbnail,
  completionRate,
  features,
  status,
  createdAt,
}: ProjectCardProps) {
  const isPackageReady = status === "package-ready";

  return (
    <Link href={`/project/${id}`}>
      <motion.div
        variants={cardHover}
        initial="initial"
        whileHover="hover"
        className={cn(
          "group relative overflow-hidden bg-bg-base border border-neutral-800 rounded-xl transition-all duration-300 hover:border-neutral-700 hover:shadow-xl cursor-pointer"
        )}
      >
        {/* Thumbnail */}
        <div className="relative aspect-video w-full bg-neutral-900 overflow-hidden">
          {thumbnail ? (
            <img
              src={thumbnail}
              alt={title}
              className="w-full h-full object-cover transition-transform duration-300 group-hover:scale-105"
            />
          ) : (
            <div className="w-full h-full flex items-center justify-center">
              <div className="text-6xl opacity-20">📦</div>
            </div>
          )}

          {/* Status badge */}
          <div className="absolute top-3 right-3">
            <span
              className={cn(
                "px-3 py-1 text-xs font-medium rounded-full backdrop-blur-sm",
                isPackageReady
                  ? "bg-orange-500/20 text-orange-400 border border-orange-500/30"
                  : "bg-neutral-800/80 text-fg-secondary border border-neutral-700"
              )}
            >
              {isPackageReady ? "Package Ready" : "Brouillon"}
            </span>
          </div>
        </div>

        {/* Content */}
        <div className="p-5 space-y-3">
          {/* Title + Description */}
          <div>
            <h3 className="text-lg font-semibold text-fg-primary mb-1 line-clamp-1">
              {title}
            </h3>
            <p className="text-sm text-fg-secondary line-clamp-2">
              {description}
            </p>
          </div>

          {/* Progress bar */}
          <div className="space-y-1.5">
            <div className="flex items-center justify-between text-xs">
              <span className="text-fg-tertiary">Progression</span>
              <span className="text-fg-secondary font-medium">
                {completionRate}%
              </span>
            </div>
            <div className="h-2 bg-neutral-900 rounded-full overflow-hidden">
              <motion.div
                initial={{ width: 0 }}
                animate={{ width: `${completionRate}%` }}
                transition={{ duration: 1, delay: 0.2 }}
                className="h-full bg-gradient-to-r from-orange-500 via-orange-600 to-orange-700 rounded-full"
              />
            </div>
          </div>

          {/* Metrics */}
          <div className="flex items-center justify-between pt-2 border-t border-neutral-800">
            <div className="flex items-center gap-4 text-xs text-fg-tertiary">
              <span className="flex items-center gap-1">
                <span className="text-fg-secondary font-medium">
                  {features}
                </span>{" "}
                fonctionnalités
              </span>
              <span>{formatRelativeTime(createdAt)}</span>
            </div>
          </div>
        </div>

        {/* Hover gradient effect */}
        <div className="absolute inset-0 bg-gradient-to-t from-orange-500/0 via-orange-500/0 to-orange-500/0 opacity-0 group-hover:opacity-5 transition-opacity duration-300 pointer-events-none" />
      </motion.div>
    </Link>
  );
}

