"use client";

import { useState, ReactNode } from "react";
import Link from "next/link";
import { usePathname } from "next/navigation";
import { motion, AnimatePresence } from "framer-motion";
import { cn } from "@/lib/utils";

interface NavItem {
  name: string;
  href: string;
  icon: string;
  subitems?: NavItem[];
}

const navItems: NavItem[] = [
  { name: "Dashboard", href: "/dashboard", icon: "📊" },
  { name: "Cortex", href: "/cortex", icon: "🧠" },
  {
    name: "Labs",
    href: "/labs/k0",
    icon: "🔬",
    subitems: [
      { name: "k0", href: "/labs/k0", icon: "🎯" },
      { name: "Brainstorming", href: "/labs/brainstorming", icon: "💡" },
      { name: "System", href: "/labs/system", icon: "🏗️" },
      { name: "Execution", href: "/labs/execution", icon: "⚡" },
      { name: "Pitch", href: "/labs/pitch", icon: "🎤" },
    ],
  },
  { name: "Projects", href: "/projects", icon: "📦" },
  { name: "Settings", href: "/settings", icon: "⚙️" },
];

interface AppShellProps {
  children: ReactNode;
}

export default function AppShell({ children }: AppShellProps) {
  const [sidebarOpen, setSidebarOpen] = useState(false);
  const [labsExpanded, setLabsExpanded] = useState(true);
  const pathname = usePathname();

  const isActive = (href: string) => pathname === href;
  const isLabsActive = pathname?.startsWith("/labs");

  return (
    <div className="flex h-screen bg-bg-base">
      {/* Sidebar Desktop */}
      <aside className="hidden lg:flex lg:flex-col lg:w-64 border-r border-neutral-800 bg-bg-elevated">
        {/* Logo */}
        <div className="h-16 flex items-center gap-2 px-6 border-b border-neutral-800">
          <div className="w-8 h-8 rounded-lg bg-gradient-to-br from-orange-500 via-orange-600 to-orange-700 flex items-center justify-center">
            <span className="text-white font-bold text-sm">k3</span>
          </div>
          <span className="text-lg font-semibold text-fg-primary">k3rn</span>
        </div>

        {/* Navigation */}
        <nav className="flex-1 overflow-y-auto p-4 space-y-1">
          {navItems.map((item) => (
            <div key={item.name}>
              {/* Main nav item */}
              {item.subitems ? (
                <button
                  onClick={() => setLabsExpanded(!labsExpanded)}
                  className={cn(
                    "w-full flex items-center justify-between gap-3 px-3 py-2 rounded-lg text-sm transition-colors duration-200",
                    isLabsActive
                      ? "bg-orange-500/10 text-orange-500"
                      : "text-fg-secondary hover:text-fg-primary hover:bg-neutral-800/50"
