"use client";

import { motion } from "framer-motion";
import { Card, CardContent, CardHeader, CardTitle, CardDescription } from "@/components/ui/Card";
import { fadeInUp, staggerContainer } from "@/lib/animations";

export default function DashboardPage() {
  const stats = [
    { label: "Projets actifs", value: "3", icon: "📦" },
    { label: "Projets complétés", value: "12", icon: "✅" },
    { label: "En cours", value: "5", icon: "⚡" },
    { label: "Total features", value: "48", icon: "🎯" },
  ];

  return (
    <div className="p-6 lg:p-8 space-y-8">
      {/* Header */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5 }}
      >
        <h1 className="text-4xl font-bold text-fg-primary mb-2">Dashboard</h1>
        <p className="text-lg text-fg-secondary">
          Vue d'ensemble de vos projets et activités k3rn
        </p>
      </motion.div>

      {/* Stats Grid */}
      <motion.div
        variants={staggerContainer}
        initial="initial"
        animate="animate"
        className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4"
      >
        {stats.map((stat, index) => (
          <motion.div key={index} variants={fadeInUp}>
            <Card hover>
              <CardContent className="p-6">
                <div className="flex items-center gap-4">
                  <div className="text-4xl">{stat.icon}</div>
                  <div>
                    <p className="text-3xl font-bold text-fg-primary">
                      {stat.value}
                    </p>
                    <p className="text-sm text-fg-secondary">{stat.label}</p>
                  </div>
                </div>
              </CardContent>
            </Card>
          </motion.div>
        ))}
      </motion.div>

      {/* Recent Activity */}
      <motion.div
        initial={{ opacity: 0, y: 20 }}
        animate={{ opacity: 1, y: 0 }}
        transition={{ duration: 0.5, delay: 0.2 }}
      >
        <Card>
          <CardHeader>
            <CardTitle>Activité récente</CardTitle>
            <CardDescription>Vos dernières actions sur k3rn</CardDescription>
          </CardHeader>
          <CardContent>
            <div className="space-y-4">
              {[1, 2, 3].map((i) => (
                <div
                  key={i}
                  className="flex items-center gap-4 p-3 rounded-lg hover:bg-neutral-900/50 transition-colors duration-200"
                >
                  <div className="w-10 h-10 rounded-full bg-orange-500/10 flex items-center justify-center text-orange-500">
                    📝
                  </div>
                  <div className="flex-1">
                    <p className="text-sm font-medium text-fg-primary">
                      Projet mis à jour
                    </p>
                    <p className="text-xs text-fg-tertiary">
                      Il y a {i} heure{i > 1 ? "s" : ""}
                    </p>
                  </div>
                </div>
              ))}
            </div>
          </CardContent>
        </Card>
      </motion.div>
    </div>
  );
}

